function Sidebar() {

  const menuClick = (name) => {

    alert(name + " page coming soon");
  };

  return (

    <div className="sidebar">

      <h2>Travel AI</h2>

      <ul>

        <li
          onClick={() =>
            menuClick("Destinations")
          }
        >
          🏖 Destinations
        </li>

        <li
          onClick={() =>
            menuClick("Budget")
          }
        >
          💰 Budget
        </li>

        <li
          onClick={() =>
            menuClick("Safety")
          }
        >
          🛡 Safety
        </li>

        <li
          onClick={() =>
            menuClick("Routes")
          }
        >
          🗺 Routes
        </li>

        <li
          onClick={() =>
            menuClick("Hotels")
          }
        >
          🏨 Hotels
        </li>

      </ul>

    </div>
  );
}

export default Sidebar;
